import os
import discord
import asyncio
from zoneinfo import ZoneInfo
from dotenv import load_dotenv
from discord.ext import tasks,commands
from datetime import datetime, timedelta, time

# TODO sometimes discord shits the bed with 503s, need to handle those errors

# TNTBOT INFO
# - TOKEN is generated by discord for the bot, must be kept secret.
# - IDs are for my own discord server and channels for testing.
# - A guild is a discord server.

DEBUG = True

TZ = ZoneInfo("America/New_York")

# BOT CONFIG
load_dotenv()
TOKEN       = os.getenv('TOKEN')
GUILD_ID    = int(os.getenv('GUILD_ID'))
EAST_ID     = int(os.getenv('EAST_ID'))
CENTRAL_ID  = int(os.getenv('CENTRAL_ID'))

ALLOWED_USERS = list(map(int, os.getenv('ALLOWED_USERS').split(',')))

TNT_CHANNELS = [EAST_ID, CENTRAL_ID]
TNT_START = datetime.now(TZ).replace(hour=18, minute=0, tzinfo=TZ)
TNT_END   = datetime.now(TZ).replace(hour=19, minute=0, tzinfo=TZ)
TNT_TIMES = [TNT_START.time(), TNT_END.time()]
TNT_TODAY = 1 # Tuesday

class AttendanceCog(commands.Cog):
    def __init__(self, bot):
        self.bot = bot
        self.join_time = {}
        self.total_time = {}
        self.member_names = {}
        self.taking_attendance = False

    def cog_unload(self):
        # Cancel tasks if cog is unloaded
        self.check_attendance.cancel()

    @commands.command()
    @commands.guild_only() # Don't allow this command in DMs, because the DM space has no ctx.
    async def attendance_start(self, ctx):
        self.check_attendance.start()
        self.taking_attendance = True
        now = datetime.now(TZ)

        # Is it TNT Today?
        if now.weekday() != TNT_TODAY and not DEBUG:
            await ctx.send("ERROR: TNT is not today.")
            return

        # If attendance tries to start after TNT_END, print error
        if now > TNT_END:
            await ctx.send("ERROR: TNT is already over.")
            return

        # If attendance was started too late (after TNT_START) check attendance right away.
        if now > TNT_START:
            await self.check_attendance()

        await ctx.send("Watching TNT channels...")

    @commands.command()
    @commands.guild_only() # Don't allow this command in DMs, because the DM space has no ctx.
    async def attendance_stop(self, ctx):
        # If attendance was stopped early, take a attendance one last time before stopping.
        if datetime.now(TZ) < TNT_END:
            await self.check_attendance()

        # Stop taking attendance
        self.check_attendance.cancel()

        # Print out attendance sheet
        if not self.total_time:
            await ctx.send("Nobody came :(")
        else:
            lines = []
            for member_id, seconds in self.total_time.items():
                name = self.member_names.get(member_id, str(member_id))
                minutes = seconds / 60
                hours = seconds / 3600
                lines.append(f"{name}: {hours:.2f}h {minutes:.2f}m {seconds:2f}s")
            await ctx.send("```\n" + "\n".join(lines) + "\n```")

        # Reset attendance
        self.taking_attendance = False
        self.join_time = {}
        self.total_time = {}
        self.member_names = {}
        await ctx.send("Stopped watching TNT channels.")

    def __flush_member(self, member_id, now):
        if member_id in self.join_time:
            session_seconds = (now - self.join_time.pop(member_id)).total_seconds()
            self.total_time[member_id] = self.total_time.get(member_id, 0) + session_seconds

    @commands.Cog.listener()
    async def on_voice_state_update(self, member, before, after):
        # This fires on every voice state event
        # So, we don't want it doing any work if the task isn't running.
        if self.taking_attendance:
            now = datetime.now(TZ)
            leave = before.channel and (before.channel.id in TNT_CHANNELS)
            enter = after.channel and (after.channel.id in TNT_CHANNELS)

            if enter and not leave:
                self.join_time[member.id] = now
                self.member_names[member.id] = member.display_name
                total = self.total_time.get(member.id, 0)
                print(f"entering {member.display_name} {total}")

            elif leave and not enter:
                self.__flush_member(member.id, now)
                total = self.total_time.get(member.id, 0)
                print(f"leaving {member.display_name} {total}")


    @tasks.loop(time = TNT_TIMES)
    async def check_attendance(self):
        now = datetime.now(TZ)

        for channel_id in TNT_CHANNELS:
            channel = self.bot.get_channel(channel_id) 

            for member in channel.members:
                if member.id not in self.join_time:
                    self.join_time[member.id] = now
                    self.member_names[member.id] = member.display_name
                else:
                    self.__flush_member(member.id, now)
                    self.join_time[member.id] = now

                total = self.total_time.get(member.id, 0) 
                print(f"{member.display_name} => {total}")


    @check_attendance.after_loop
    async def after_check_attendance(self):
        self.bot.dispatch("attendance_taken")

    def guild_name(self):
        guild = self.bot.get_guild(GUILD_ID)
        return guild.name

    @check_attendance.before_loop
    async def before_check_attendance(self):
        print("Waiting until time")
        await self.bot.wait_until_ready()

    @commands.command()
    @commands.guild_only() # Don't allow this command in DMs, because the DM space has no ctx.
    async def list_users(self, ctx, *, channel_name: str):
        channel_id = 0
        channel = discord.utils.get(ctx.guild.channels, name=channel_name)
        if channel:
            members = channel.members
            out = ""
            for member in members:
                out = out + member.display_name + "\n"
            await ctx.send(f"Members in Channel {channel.name} ({channel.id}) \n{out}")
        else:
            await ctx.send("ERROR Channel Not Found")

    @commands.command()
    @commands.guild_only() # Don't allow this command in DMs, because the DM space has no ctx.
    async def announce_tnt(self, ctx):
        start = int(TNT_START.timestamp()) 
        end = int(TNT_END.timestamp()) 
        message = f"""
Trenched n' Tuesday <t:{start}:R>. Let’s get to seeding. 

Official Run Time: <t:{start}:t> to <t:{end}:t> To Earn Operational Credit: Be in either Tactical Realism East or Central voice channels AND play on our servers for at least 1 hour total 

7th Cav Squad Limits: 
4 in infantry 
2 in tanks and artillery
1 in recon

Please do not :lock: squads (after all, this is a community/recruiting event)
"""
        await ctx.send(message)

class TNTBot(commands.Bot):
    def __init__(self):
        guild = None
        intents = discord.Intents.default()
        intents.members = True           # Required to see member lists
        intents.voice_states = True      # Required to see who is in voice channels
        intents.message_content = True   # Required to read command messages
        intents.messages = True          # Required to send messages
        intents.guilds = True            # Required to access guild/channel info
        super().__init__(command_prefix="!", intents=intents)

    async def setup_hook(self):
        print("AttendanceCog loaded.")
        await self.add_cog(AttendanceCog(bot))

    async def on_ready(self):
        print(f"Logged in as {self.user}")
        print("Registered commands:")
        for command in self.commands:
            print(f"- {command.name}")
        self.guild = self.get_guild(GUILD_ID)
        if self.guild is None:
            print(f"Could not find guild with ID {GUILD_ID}. "
                  "ERROR: Make sure the bot has been invited to that server.")
            return

    async def on_message(self, message):
        if (message.author.id in ALLOWED_USERS):
            print(f"{message.content}")
            await self.process_commands(message)

    async def on_command_error(self, ctx, error):
        if isinstance(error, commands.CommandNotFound):
            await ctx.send(f"Unknown command. Use `{ctx.prefix}help` to see available commands.")
            return
        elif isinstance(error, commands.MissingRequiredArgument):
            await ctx.send(f"Error: Missing Required Arugment(s)")
            return
        raise error

class HelpCommand(commands.MinimalHelpCommand):
    async def send_pages(self):
        destination = self.get_destination()
        for page in self.paginator.pages:
            emby = discord.Embed(description=page)
            await destination.send(embed=emby)

bot = TNTBot()
bot.help_command = HelpCommand()
bot.run(TOKEN)
